insert into public.regions (id, slug, status, data, updated_at) values
  ('reg_deep_south', 'deep-south', null, '{"id":"reg_deep_south","slug":"deep-south","label":"Deep South & Gulf","zoneRange":"USDA 8–10","note":"Long, humid summers. Heat and disease pressure, not cold, are the limiting factors. Reblooming and heat-set breeding matters most here."}'::jsonb, now()),
  ('reg_mid_atlantic', 'mid-atlantic', null, '{"id":"reg_mid_atlantic","slug":"mid-atlantic","label":"Mid-Atlantic","zoneRange":"USDA 6–8","note":"Humid August; Septoria and downy mildew country. Most of the independent nativar trial data comes from here — which is also its limitation."}'::jsonb, now()),
  ('reg_northeast', 'northeast', null, '{"id":"reg_northeast","slug":"northeast","label":"Northeast & New England","zoneRange":"USDA 4–6","note":"Old-wood bloomers lose flowers in a hard winter. Bud hardiness, not stem hardiness, is the number that matters and almost nobody publishes it."}'::jsonb, now()),
  ('reg_midwest', 'midwest', null, '{"id":"reg_midwest","slug":"midwest","label":"Midwest & Great Lakes","zoneRange":"USDA 4–6","note":"Continental extremes. Note Proven Winners’ own warning that some zone-6b plants suit mild coastal 6b and not harsh interior sites."}'::jsonb, now()),
  ('reg_mountain_west', 'mountain-west', null, '{"id":"reg_mountain_west","slug":"mountain-west","label":"Mountain West & High Plains","zoneRange":"USDA 3–6","note":"Low humidity, intense radiation, late frosts. Kaolin and shade have a stronger case here than in humid regions."}'::jsonb, now()),
  ('reg_southwest', 'southwest', null, '{"id":"reg_southwest","slug":"southwest","label":"Southwest & Desert","zoneRange":"USDA 8–10","note":"Where deficit irrigation and WaterSense controllers pay back fastest — and where biochar’s tropical-soil evidence is least irrelevant."}'::jsonb, now()),
  ('reg_pacific_nw', 'pacific-northwest', null, '{"id":"reg_pacific_nw","slug":"pacific-northwest","label":"Pacific Northwest","zoneRange":"USDA 7–9","note":"Cool summers mean shade cloth is of negative value — light is already the limiting factor. Slug pressure makes no-dig a harder sell."}'::jsonb, now()),
  ('reg_california', 'california', null, '{"id":"reg_california","slug":"california","label":"California & Mediterranean","zoneRange":"USDA 8–10","note":"Low-chill fruit breeding is a live issue here, and chill accumulation is falling. The hardiness map is close to useless."}'::jsonb, now())
